import { Component, OnInit } from '@angular/core';
import { ContenidoService } from '../../shared/services/contenido.service';

@Component({
  selector: 'app-inicio',
  templateUrl: './inicio.component.html',
  styleUrls: ['./inicio.component.css']
})
export class InicioComponent implements OnInit {
  contenido: any = {
    hero: {
      titulo: '',
      subtitulo: '',
      descripcion: '',
      cta_texto: '',
      cta_link: '',
      imagen: ''
    },
    servicios_destacados: [],
    estadisticas: {
      clientes_satisfechos: '',
      proyectos_completados: '',
      años_experiencia: '',
      equipo_profesional: ''
    }
  };

  constructor(private contenidoService: ContenidoService) {}

  ngOnInit(): void {
    this.loadContent();
  }

  private loadContent(): void {
    this.contenidoService.getContenido().subscribe({
      next: (data) => {
        if (data && data.inicio) {
          this.contenido = data.inicio;
        }
      },
      error: (error) => {
        console.error('Error loading content:', error);
      }
    });
  }
}
<!-- Hero Section -->
<section class="container flex items-center justify-between min-h-[80vh] py-24 gap-16">
  <div class="flex-1 max-w-2xl animate-fade-in">
    <h1 class="text-5xl font-extrabold leading-tight mb-4 bg-gradient-to-r from-primary to-secondary bg-clip-text text-transparent">
      {{contenido.hero.titulo}}
    </h1>
    <h2 class="text-2xl font-medium text-text-color mb-6">{{contenido.hero.subtitulo}}</h2>
    <p class="text-lg text-text-light mb-8">{{contenido.hero.descripcion}}</p>
    <a [routerLink]="[contenido.hero.cta_link]" class="btn btn-primary">{{contenido.hero.cta_texto}}</a>
  </div>
  <div class="flex-1 max-w-xl animate-slide-in">
    <img [src]="contenido.hero.imagen" alt="BOOST AGENCY Hero" class="w-full h-auto rounded-3xl shadow-2xl">
  </div>
</section>

<!-- Services Section -->
<section class="bg-background-light py-24">
  <div class="container">
    <h2 class="section-title">Nuestros Servicios</h2>
    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
      <div class="card" *ngFor="let servicio of contenido.servicios_destacados">
        <i [class]="servicio.icono" class="text-4xl text-primary mb-6"></i>
        <h3 class="text-2xl font-semibold mb-4 text-text-color">{{servicio.titulo}}</h3>
        <p class="text-text-light mb-6">{{servicio.descripcion}}</p>
        <a [routerLink]="[servicio.link]" class="text-primary font-medium hover:text-blue-600 transition-colors">
          Saber más
        </a>
      </div>
    </div>
  </div>
</section>

<!-- Stats Section -->
<section class="py-24">
  <div class="container">
    <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
      <div class="text-center">
        <h3 class="text-4xl font-bold text-primary mb-2">{{contenido.estadisticas.clientes_satisfechos}}</h3>
        <p class="text-text-light text-lg">Clientes Satisfechos</p>
      </div>
      <div class="text-center">
        <h3 class="text-4xl font-bold text-primary mb-2">{{contenido.estadisticas.proyectos_completados}}</h3>
        <p class="text-text-light text-lg">Proyectos Completados</p>
      </div>
      <div class="text-center">
        <h3 class="text-4xl font-bold text-primary mb-2">{{contenido.estadisticas['años_experiencia']}}</h3>
        <p class="text-text-light text-lg">Años de Experiencia</p>
      </div>
      <div class="text-center">
        <h3 class="text-4xl font-bold text-primary mb-2">{{contenido.estadisticas.equipo_profesional}}</h3>
        <p class="text-text-light text-lg">Profesionales</p>
      </div>
    </div>
  </div>
</section>

<!-- CTA Section -->
<section class="bg-gradient-to-r from-primary to-secondary text-white py-24">
  <div class="container text-center">
    <h2 class="text-4xl font-bold mb-4">¿Listo para impulsar tu negocio?</h2>
    <p class="text-xl opacity-90 mb-8">Únete a cientos de empresas que ya confían en nosotros</p>
    <a routerLink="/el-futuro-es-ahora" class="bg-white text-primary px-10 py-4 rounded-full font-semibold hover:-translate-y-0.5 hover:shadow-lg transition-all duration-300 inline-block">
      Comienza Ahora
    </a>
  </div>
</section>
